/**
 * Abstract base class for all data sources in a pipeline.
 *
 * @remarks
 *
 * Extend `DataSource` to implement a concrete data source. Subclasses must override the abstract {@link DataSource.connect} and {@link DataSource.fetch} methods. The {@link DataSource.disconnect} method provides a no-op default that subclasses may override as needed.
 *
 * @typeParam T - The type of records produced by this data source.
 *
 * @throws
 *
 * {@link DataSourceError} if the underlying resource cannot be accessed.
 *
 * @example
 * ```typescript
 * import { DataSource } from "kitchensink";
 *
 * class NumberSource extends DataSource<number> {
 * 	readonly name = "NumberSource";
 *
 * 	async connect(): Promise<void> {
 * 		// establish connection
 * 	}
 *
 * 	async fetch(): Promise<number[]> {
 * 		return [1, 2, 3];
 * 	}
 * }
 *
 * const src = new NumberSource();
 * await src.connect();
 * const records = await src.fetch();
 * src.disconnect();
 * ```
 *
 * @see
 *
 * Pipeline
 *
 * @public
 */

